import { describe, expect, test } from "bun:test";
import { automation, code, every, isAutomationDefinition, ref } from "./index";

describe("automation() builder", () => {
  test("builds an automation with schedule trigger and internal flow", () => {
    const definition = automation("amazon-legal-disclosures")
      .title("Amazon legal disclosures")
      .description("Sends legal disclosure PDFs to eligible Amazon buyers.")
      .sourceFile("dypai/automations/amazon-legal-disclosures.automation.ts")
      .schedule(every.dayAt("10:00", { timezone: "Europe/Madrid" }))
      .requiresSecrets({
        amazon_refresh_token: { label: "Amazon Refresh Token", sensitive: true },
      })
      .requiresFiles({
        declaration_es: { label: "PDF Spain", accept: "application/pdf" },
      })
      .history({
        table: "legal_disclosure_sends",
        idempotencyKey: "amazon_order_id",
      })
      .notify({
        when: "run.failed",
        channels: ["email", "agent"],
      })
      .step("list_orders", code(() => ({ ok: true })))
      .return({ ok: ref.literal(true) });

    expect(definition.kind).toBe("automation");
    expect(definition.name).toBe("amazon-legal-disclosures");
    expect(definition.title).toBe("Amazon legal disclosures");
    expect(definition.trigger).toEqual({
      type: "schedule",
      cron: "0 10 * * *",
      timezone: "Europe/Madrid",
    });
    expect(definition.flow.trigger).toEqual({
      type: "schedule",
      cron: "0 10 * * *",
      timezone: "Europe/Madrid",
    });
    expect(definition.flow.auth).toEqual({ mode: "api_key" });
    expect(definition.requirements).toHaveLength(2);
    expect(definition.requirements[0]).toMatchObject({
      type: "secret",
      key: "amazon_refresh_token",
      sensitive: true,
    });
    expect(definition.requirements[1]).toMatchObject({
      type: "file",
      key: "declaration_es",
      accept: "application/pdf",
    });
    expect(definition.notifications[0]?.channels).toEqual(["email", "agent"]);
    expect(isAutomationDefinition(definition)).toBe(true);
  });

  test("notify normalizes channels and defaults unknown values away", () => {
    const definition = automation("notify-test")
      .schedule(every.hour())
      .notify({
        when: "run.failed",
        // @ts-expect-error invalid channel is stripped at runtime
        channels: ["agent", "invalid", "email", "agent"],
      })
      .step("main", code(() => ({ ok: true })))
      .return({ ok: ref.literal(true) });

    expect(definition.notifications[0]?.channels).toEqual(["agent", "email"]);
  });

  test("missing trigger fails clearly", () => {
    expect(() =>
      automation("no-trigger")
        .step("main", code(() => ({ ok: true })))
        .return({ ok: ref.literal(true) }),
    ).toThrow(/must declare .schedule/);
  });

  test("webhook automation preserves webhook trigger on internal flow", () => {
    const definition = automation("stripe-events")
      .webhook({ provider: "stripe", event: "payment_intent.succeeded" })
      .step("main", code(() => ({ ok: true })))
      .return({ ok: ref.literal(true) });

    expect(definition.trigger?.type).toBe("webhook");
    expect(definition.flow.trigger).toMatchObject({
      type: "webhook",
      provider: "stripe",
      event: "payment_intent.succeeded",
    });
  });
});
